using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    #region CreateOrder — Happy Path

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(9.99m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 5.50m, Quantity = 3 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        // 10.00*2 + 5.50*3 = 20.00 + 16.50 = 36.50
        Assert.AreEqual(36.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCustomerId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-42", items);

        // Assert
        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsNonNullId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsItemsReference()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);
        var after = DateTime.UtcNow;

        // Assert
        Assert.IsTrue(order.CreatedAt >= before, $"CreatedAt {order.CreatedAt} should be >= {before}");
        Assert.IsTrue(order.CreatedAt <= after, $"CreatedAt {order.CreatedAt} should be <= {after}");
    }

    #endregion

    #region CreateOrder — Edge Cases

    [TestMethod]
    [DataRow(5, DisplayName = "Quantity of 5")]
    [DataRow(100, DisplayName = "Quantity of 100")]
    public void CreateOrder_ItemWithQuantityGreaterThanOne_MultipliesPriceByQuantity(int quantity)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 7.25m, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(7.25m * quantity, order.Total);
    }

    [TestMethod]
    public void CreateOrder_DecimalPrices_CalculatesTotalPrecisely()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item A", Price = 0.10m, Quantity = 3 },
            new() { ProductName = "Item B", Price = 19.99m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        // 0.10*3 + 19.99*1 = 0.30 + 19.99 = 20.29
        Assert.AreEqual(20.29m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_StoresBothOrders()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 1.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "B", Price = 2.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-1", items1);
        var order2 = _sut.CreateOrder("cust-1", items2);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
        var allOrders = _sut.GetOrdersByCustomer("cust-1");
        Assert.AreEqual(2, allOrders.Count);
    }

    #endregion

    #region CreateOrder — Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", items));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 2 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual("cust-1", retrieved.CustomerId);
        Assert.AreEqual(10.00m, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_AfterMultipleCreations_ReturnsCorrectOrder()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 1.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "B", Price = 2.00m, Quantity = 1 }
        };
        var order1 = _sut.CreateOrder("cust-1", items1);
        var order2 = _sut.CreateOrder("cust-2", items2);

        // Act
        var retrieved = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(order2.Id, retrieved.Id);
        Assert.AreEqual("cust-2", retrieved.CustomerId);
        Assert.AreEqual(2.00m, retrieved.Total);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsTheirOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 3.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        // Act
        var orders = _sut.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.AreEqual(1, orders.Count);
        Assert.AreEqual(created.Id, orders[0].Id);
        Assert.AreEqual(3.00m, orders[0].Total);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        // Act
