        // Assert
        Assert.AreEqual(0, orders.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrdersSameCustomer_ReturnsAllOrders()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 1.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "B", Price = 2.00m, Quantity = 1 }
